// This script processes a MobSF JSON report to extract used and detected libraries.

for (const item of $input.all()) {
  const mobsfReport = item.json.json || item.json;

  // List 1: Packages found in code analysis (i.e., "used")
  const usedPackages = new Set();
  if (mobsfReport.code_analysis && mobsfReport.code_analysis.findings) {
    for (const key of Object.keys(mobsfReport.code_analysis.findings)) {
        const finding = mobsfReport.code_analysis.findings[key];
        if (finding.files) {
            for (const filePath of Object.keys(finding.files)) {
                const parts = filePath.split('/');
                if (parts.length > 1) {
                    parts.pop(); // remove filename
                    const packageName = parts.join('.');
                    usedPackages.add(packageName);
                }
            }
        }
    }
  }

  // List 2: Packages detected from Android components (proxy for "declared/included")
  const detectedComponents = [
      ...(mobsfReport.activities || []),
      ...(mobsfReport.receivers || []),
      ...(mobsfReport.providers || []),
      ...(mobsfReport.services || []),
      ...(mobsfReport.libraries || [])
  ];

  const detectedPackages = new Set();
  for (const componentPath of detectedComponents) {
      const parts = componentPath.split('.');
      if (parts.length > 1) {
          // Heuristic: if a component name is very long, it's likely a specific class.
          // We take the first 2 or 3 parts as the base package name.
          // e.g., com.google.android.gms.measurement.AppMeasurementReceiver -> com.google.android.gms
          let packageParts;
          if (parts[0] === 'com' && parts[1] === 'google') {
              packageParts = parts.slice(0, 4); // e.g., com.google.android.gms
          } else if (parts[0] === 'androidx') {
              packageParts = parts.slice(0, 2); // e.g., androidx.core
          } else {
              packageParts = parts.slice(0, 2); // e.g., io.livekit
          }
          if (packageParts.length > 0) {
              detectedPackages.add(packageParts.join('.'));
          }
      }
  }

  // Overwrite the original json with the new lists
  item.json = {
    usedPackages: Array.from(usedPackages).sort(),
    detectedPackages: Array.from(detectedPackages).sort()
  };
}

// Return the modified items
return $input.all();

const item = $input.item.json;

const used = new Set(item.usedPackages);
const detected = item.detectedPackages;

const unused = detected.filter(pkg => {
  return !Array.from(used).some(u => u.startsWith(pkg));
});

return [{
  json: {
    usedPackages: item.usedPackages,
    detectedPackages: item.detectedPackages,
    unusedPackages: unused
  }
}];

const unused = $json.unusedPackages || [];

const risky = [];
const maybe = [];
const safe = [];

// Rules
for (const lib of unused) {

  // RISKY: required by Google / Firebase / Android system
  if (
    lib.startsWith("com.google.android.gms") ||
    lib.startsWith("com.google.firebase") ||
    lib.startsWith("androidx.startup") ||
    lib.startsWith("com.google.android.datatransport")
  ) {
    risky.push(lib);
    continue;
  }

  // MAYBE: could be auto-included by Gradle or React Native
  if (
    lib.startsWith("com.jakewharton") ||
    lib.startsWith("androidx.profileinstaller")
  ) {
    maybe.push(lib);
    continue;
  }

  // SAFE: camera, mlkit, unused modules, etc.
  safe.push(lib);
}

return [{
  json: {
    unusedPackages: unused,
    safeToRemove: safe,
    maybeRequired: maybe,
    riskyToRemove: risky
  }
}];
